const san=s=>{if(typeof s!=="string")return s;return s.replace(/[<>"'&]/g,c=>({"<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#x27;","&":"&amp;"}[c]||c)).trim().slice(0,2000)};
const gid=()=>`${Date.now()}-${Math.random().toString(36).slice(2,8)}`;
const hpw=p=>{let h=0;for(let i=0;i<p.length;i++){h=((h<<5)-h+p.charCodeAt(i))|0;}return`a$${Math.abs(h).toString(36)}`};
const drift=(pts,w=7)=>{if(!pts||pts.length<6)return{score:0,trend:"stable",sev:"none",aR:0,aO:0};const r=pts.slice(-w),o=pts.slice(-w*2,-w);if(!o.length)return{score:0,trend:"stable",sev:"none",aR:0,aO:0};const aR=r.reduce((a,b)=>a+b,0)/r.length,aO=o.reduce((a,b)=>a+b,0)/o.length;const d=((aR-aO)/aO)*100,ad=Math.abs(d);return{score:Math.round(d*100)/100,trend:d>0.5?"up":d<-0.5?"down":"stable",sev:ad>15?"critical":ad>8?"significant":ad>3?"low":"none",aR:Math.round(aR*10)/10,aO:Math.round(aO*10)/10}};
const sovCalc=(ag,dec,inc)=>{const n=ag.length||1;const gov=ag.filter((a: any) =>a.st==="active"&&a.gl>=2).length/n;const cd=dec.filter((d: any) =>d.crit==="high"||d.crit==="critical").length;const ho=dec.filter((d: any) =>d.auth==="human_only").length;const hc=cd>0?ho/cd:1;const ip=Math.min(inc.filter((i: any) =>Date.now()-i.ts<30*86400000).length*5,30);const ah=ag.reduce((s,a)=>s+a.hp,0)/n;return Math.max(0,Math.min(100,Math.round(gov*25+hc*25+(ah/100)*25+((100-ip)/100*25))))};

